import React, { useEffect, useState } from "react";

function Notifications({ currentUser }) {
  const [updates, setUpdates] = useState([]);
  useEffect(() => {
    if (!currentUser || currentUser.role !== 'POSTER') return;
    fetch(`http://localhost:8080/api/tasks/poster/${currentUser.id}`)
      .then(res => res.json())
      .then(tasks => {
        // Only show tasks that have been accepted by at least one hustler
        const accepted = tasks.filter(t => t.acceptedHustlers && t.acceptedHustlers.length > 0);
        setUpdates(accepted);
      });
  }, [currentUser]);

  if (!currentUser || currentUser.role !== 'POSTER') return <div className="text-white">Login as a poster to see updates.</div>;

  return (
    <div className="max-w-xl mx-auto bg-[#1a2233] p-6 rounded mt-8 shadow">
      <h2 className="text-2xl font-bold text-yellow-300 mb-4">Task Updates</h2>
      {updates.length === 0 ? (
        <div className="text-gray-400">No new updates yet.</div>
      ) : (
        <ul className="space-y-4">
          {updates.map(task => (
            <li key={task.id} className="bg-[#232b3d] p-4 rounded">
              <div className="font-semibold text-lg text-yellow-300">{task.title}</div>
              <div className="text-white mb-2">Accepted by: {task.acceptedHustlers.map(u => u.username).join(', ')}</div>
              <div className="text-gray-400 text-sm">Budget: {task.budget} | Status: {task.status}</div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Notifications;
